     1→/**
     2→ * Template Store
     3→ * Manages task templates for recurring tasks
     4→ *
     5→ * Templates store reusable task configurations (description, checklist, tags, custom fields)
     6→ * that can be automatically applied to recurring task instances.
     7→ */
     8→
     9→import { create } from 'zustand';
    10→import { persist, createJSONStorage } from 'zustand/middleware';
    11→import type { TaskTemplate, Task } from '../types';
    12→import { createSyncedStorage } from '../lib/syncedStorage';
    13→import { logger } from '../services/logger';
    14→
    15→const log = logger.module('TemplateStore');
    16→
    17→interface TemplateState {
    18→  templates: TaskTemplate[];
    19→
    20→  // Actions
    21→  createTemplate: (task: Partial<Task>) => TaskTemplate;
    22→  updateTemplate: (id: string, updates: Partial<TaskTemplate>) => void;
    23→  deleteTemplate: (id: string) => void;
    24→  getTemplate: (id: string) => TaskTemplate | undefined;
    25→}
    26→
    27→export const useTemplateStore = create<TemplateState>()(
    28→  persist(
    29→    (set, get) => ({
    30→      templates: [],
    31→
    32→      /**
    33→       * Create a new template from a task
    34→       * Extracts only template-relevant fields (description, checklist, tags, custom fields)
    35→       */
    36→      createTemplate: (task: Partial<Task>): TaskTemplate => {
    37→        const now = new Date().toISOString();
    38→        const template: TaskTemplate = {
    39→          id: `template-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
    40→          name: task.title || 'Untitled Template',
    41→          description: task.description || '',
    42→          checklist: task.checklist?.map(item => ({
    43→            ...item,
    44→            completed: false, // Reset completion status
    45→          })),
    46→          tags: task.tags || [],
    47→          customFields: task.customFields ? { ...task.customFields } : undefined,
    48→          createdAt: now,
    49→          updatedAt: now,
    50→        };
    51→
    52→        set((state) => ({
    53→          templates: [...state.templates, template],
    54→        }));
    55→
    56→        log.info('Created template', { templateId: template.id, name: template.name });
    57→        return template;
    58→      },
    59→
    60→      /**
    61→       * Update an existing template
    62→       */
    63→      updateTemplate: (id: string, updates: Partial<TaskTemplate>): void => {
    64→        set((state) => ({
    65→          templates: state.templates.map((template) =>
    66→            template.id === id
    67→              ? {
    68→                  ...template,
    69→                  ...updates,
    70→                  updatedAt: new Date().toISOString(),
    71→                }
    72→              : template
    73→          ),
    74→        }));
    75→
    76→        log.info('Updated template', { templateId: id, updates });
    77→      },
    78→
    79→      /**
    80→       * Delete a template
    81→       * Note: Does not affect existing recurring tasks using this template
    82→       */
    83→      deleteTemplate: (id: string): void => {
    84→        set((state) => ({
    85→          templates: state.templates.filter((template) => template.id !== id),
    86→        }));
    87→
    88→        log.info('Deleted template', { templateId: id });
    89→      },
    90→
    91→      /**
    92→       * Get a template by ID
    93→       */
    94→      getTemplate: (id: string): TaskTemplate | undefined => {
    95→        return get().templates.find((template) => template.id === id);
    96→      },
    97→    }),
    98→    {
    99→      name: 'template-storage',
   100→      storage: createJSONStorage(() => createSyncedStorage()),
   101→      version: 1,
   102→      partialize: (state) => ({
   103→        templates: state.templates,
   104→      }),
   105→    }
   106→  )
   107→);
   108→

