   184→/**
   185→ * Sort notes based on sort config
   186→ */
   187→const sortNotes = (notes: Note[], config: NoteSortConfig): Note[] => {
   188→  const sorted = [...notes];
   189→
   190→  sorted.sort((a, b) => {
   191→    let comparison = 0;
   192→
   193→    switch (config.field) {
   194→      case 'title':
   195→        comparison = a.title.localeCompare(b.title);
   196→        break;
   197→      case 'createdAt':
   198→        comparison = a.createdAt.getTime() - b.createdAt.getTime();
   199→        break;
   200→      case 'updatedAt':
   201→        comparison = a.updatedAt.getTime() - b.updatedAt.getTime();
   202→        break;
   203→      case 'manual':
   204→        // Manual sort - preserve order (could add sortOrder field in future)
   205→        comparison = 0;
   206→        break;
   207→    }
   208→
   209→    return config.order === 'asc' ? comparison : -comparison;
   210→  });
   211→
   212→  // Always pin pinned notes to top
   213→  return sorted.sort((a, b) => {
   214→    if (a.isPinned && !b.isPinned) return -1;
   215→    if (!a.isPinned && b.isPinned) return 1;
   216→    return 0;
   217→  });
   218→};
