   220→/**
   221→ * Filter notes based on filter type
   222→ */
   223→const filterNotes = (notes: Note[], filter: NoteFilter): Note[] => {
   224→  switch (filter) {
   225→    case 'favorites':
   226→      return notes.filter((note) => note.isFavorite);
   227→    case 'pinned':
   228→      return notes.filter((note) => note.isPinned);
   229→    case 'archived':
   230→      return notes.filter((note) => note.isArchived);
   231→    case 'unarchived':
   232→      return notes.filter((note) => !note.isArchived);
   233→    case 'all':
   234→    default:
   235→      return notes;
   236→  }
   237→};
