    defaultTags: ['project'],
    isBuiltIn: true,
  },
  {
    id: 'todo-list',
    name: 'Todo List',
    description: '## Todo List\n\n### High Priority\n- [ ] \n\n### Medium Priority\n- [ ] \n\n### Low Priority\n- [ ] \n\n### Completed\n- [x] \n',
    icon: '✅',
    category: 'Productivity',
