    isBuiltIn: true,
  },
  {
    id: 'weekly-review',
    name: 'Weekly Review',
    description: '## Weekly Review\n\n**Week of:** \n\n### Accomplishments\n- \n\n### Challenges\n- \n\n### Lessons Learned\n- \n\n### Next Week\'s Goals\n- [ ] \n\n### Notes\n',
    icon: '📅',
    category: 'Personal',
    defaultTags: ['review', 'weekly'],
    isBuiltIn: true,
  },
