     1→/**
     2→ * Data Validation Service
     3→ *
     4→ * Centralized validation for data entering stores.
     5→ * Focused on import validation to prevent data corruption.
     6→ *
     7→ * Design Principles:
     8→ * - Lean: Only validate critical fields, not every property
     9→ * - Safe: Invalid data rejected before persistence
    10→ * - Informative: Clear error messages for debugging
    11→ */
    12→
    13→import { z } from 'zod';
    14→import { logger } from './logger';
    15→
    16→const log = logger.module('Validation');
    17→
    18→// ==================== DATE KEY VALIDATION ====================
    19→
    20→/**
    21→ * Standard date key format: YYYY-M-D (1-indexed month, no padding)
    22→ * Examples: "2025-1-15" (Jan 15), "2025-12-31" (Dec 31)
    23→ */
    24→export const DateKeySchema = z.string().regex(
    25→  /^\d{4}-(1[0-2]|[1-9])-(3[01]|[12]\d|[1-9])$/,
    26→  'Invalid date key. Expected: YYYY-M-D (e.g., 2025-1-15)'
    27→);
    28→
    29→/**
    30→ * Time format: HH:mm (24-hour)
    31→ */
    32→export const TimeSchema = z.string().regex(
    33→  /^([01]\d|2[0-3]):[0-5]\d$/,
    34→  'Invalid time. Expected: HH:mm (e.g., 14:30)'
    35→);
    36→
    37→// ==================== CALENDAR EVENT VALIDATION ====================
    38→
    39→export const RecurrenceSchema = z.object({
    40→  frequency: z.enum(['daily', 'weekly', 'monthly', 'yearly']),
    41→  interval: z.number().int().positive(),
    42→  daysOfWeek: z.array(z.number().int().min(0).max(6)).optional(),
    43→  dayOfMonth: z.number().int().min(1).max(31).optional(),
    44→  endType: z.enum(['never', 'after', 'until']),
    45→  endCount: z.number().int().positive().optional(),
    46→  endDate: z.string().optional(),
    47→}).optional();
    48→
    49→export const CalendarEventSchema = z.object({
    50→  id: z.string().min(1, 'Event ID required'),
    51→  title: z.string().min(1, 'Event title required'),
    52→  description: z.string().optional(),
    53→  startTime: TimeSchema.optional(),
    54→  endTime: TimeSchema.optional(),
    55→  isAllDay: z.boolean().optional(),
    56→  recurrence: RecurrenceSchema,
    57→  recurrenceId: z.string().optional(),
    58→  recurrenceException: z.boolean().optional(),
    59→  endDate: z.string().optional(),
    60→  reminders: z.array(z.number()).optional(),
    61→  location: z.string().optional(),
    62→}).passthrough(); // Allow internal fields like _isMultiDayPart
    63→
    64→// ==================== TASK VALIDATION ====================
    65→
    66→export const TaskSchema = z.object({
    67→  id: z.string().min(1, 'Task ID required'),
    68→  title: z.string().min(1, 'Task title required'),
    69→  status: z.enum(['backlog', 'todo', 'inprogress', 'review', 'done']),
    70→  created: z.string(),
    71→  priority: z.enum(['low', 'medium', 'high']),
    72→}).passthrough(); // Allow additional fields
    73→
    74→// ==================== NOTE VALIDATION ====================
    75→
    76→export const NoteSchema = z.object({
    77→  id: z.string().min(1, 'Note ID required'),
    78→  title: z.string(),
    79→  content: z.string(),
    80→  folderId: z.string().nullable(),
    81→  createdAt: z.union([z.string(), z.date()]),
    82→  updatedAt: z.union([z.string(), z.date()]),
    83→}).passthrough();
    84→
    85→// ==================== BRAIN BACKUP VALIDATION ====================
    86→
    87→export const BrainBackupSchema = z.object({
    88→  version: z.string().optional(),
    89→  appVersion: z.string().optional(),
    90→  exportDate: z.string().optional(),
    91→  compressed: z.boolean().optional(),
    92→  data: z.record(z.unknown()),
    93→});
    94→
    95→// ==================== VALIDATION RESULTS ====================
    96→
    97→export interface ValidationError {
    98→  field: string;
    99→  message: string;
   100→  value?: unknown;
   101→}
   102→
   103→export interface ValidationResult<T> {
   104→  success: boolean;
   105→  data?: T;
   106→  errors?: ValidationError[];
   107→}
   108→
   109→// ==================== VALIDATION FUNCTIONS ====================
   110→
   111→/**
   112→ * Validate a single value against a schema
   113→ */
   114→export function validate<T>(
   115→  schema: z.ZodSchema<T>,
   116→  value: unknown,
   117→  context?: string
   118→): ValidationResult<T> {
   119→  const result = schema.safeParse(value);
   120→
   121→  if (result.success) {
   122→    return { success: true, data: result.data };
   123→  }
   124→
   125→  const errors: ValidationError[] = result.error.issues.map(issue => ({
   126→    field: issue.path.join('.') || context || 'root',
   127→    message: issue.message,
   128→    value: issue.path.length > 0 ? getNestedValue(value, issue.path) : value,
   129→  }));
   130→
   131→  log.warn('Validation failed', { context, errors: errors.slice(0, 3) });
   132→
   133→  return { success: false, errors };
   134→}
   135→
   136→/**
   137→ * Validate and throw on failure
   138→ */
   139→export function validateOrThrow<T>(
   140→  schema: z.ZodSchema<T>,
   141→  value: unknown,
   142→  context: string
   143→): T {
   144→  const result = validate(schema, value, context);
   145→
   146→  if (!result.success) {
   147→    const errorMsg = result.errors?.map(e => `${e.field}: ${e.message}`).join(', ');
   148→    throw new Error(`Validation failed for ${context}: ${errorMsg}`);
   149→  }
   150→
   151→  return result.data!;
   152→}
   153→
   154→/**
   155→ * Validate calendar events for import
   156→ * Returns valid events and collects errors for invalid ones
   157→ */
   158→export function validateCalendarEvents(
   159→  events: Record<string, unknown[]>
   160→): {
   161→  valid: Record<string, unknown[]>;
   162→  errors: Array<{ dateKey: string; eventIndex: number; errors: ValidationError[] }>;
